const staticData = $getWorkflowStaticData('global');

// Auto-reset for each new workflow execution
if (staticData.lastExecutionId !== $execution.id) {
  staticData.retryCount = 0;
  staticData.lastExecutionId = $execution.id;
}

const retryCount = (staticData.retryCount || 0) + 1;
staticData.retryCount = retryCount;

const taskId = $input.first().json.data?.taskId || $input.first().json.taskId;

return [{ json: { retryCount, taskId } }];

const input = $input.first().json;
const formData = $('On form submission').item.json;
let subject, body;

if (input.data?.state === 'fail') {
  subject = 'Infographic generation failed';
  body = `Hi,

The infographic generation failed.

**Error Details:**
${input.data.errorMessage || 'Unknown error'}

**Task ID:** ${input.data.taskId || input.taskId || 'unknown'}

**Original Request:**
- Headline: ${formData['Main Headline']}
- Data Points: ${formData['Key Data Points']}
- Style: ${formData['Art Style']}
- Layout: ${formData['Layout Structure']}
- Aspect Ratio: ${formData['Aspect Ratio']}
- Resolution: ${formData['Resolution']}`;
} else if (input.retryCount !== undefined) {
  subject = 'Infographic generation timed out';
  body = `Hi,

The infographic generation timed out after 20 polling attempts.

**Task ID:** ${input.taskId || 'unknown'}

**Original Request:**
- Headline: ${formData['Main Headline']}
- Data Points: ${formData['Key Data Points']}
- Style: ${formData['Art Style']}
- Layout: ${formData['Layout Structure']}
- Aspect Ratio: ${formData['Aspect Ratio']}
- Resolution: ${formData['Resolution']}

Please check the kie.ai dashboard for more details.`;
} else {
  subject = 'Infographic API Error';
  body = `Hi,

An API error occurred during infographic generation.

**Error Details:**
${JSON.stringify(input, null, 2)}

**Original Request:**
- Headline: ${formData['Main Headline']}
- Data Points: ${formData['Key Data Points']}
- Style: ${formData['Art Style']}
- Layout: ${formData['Layout Structure']}`;
}

return [{ json: { subject, body } }];
